static async void AddFace(string subscription_key, string personGroupId, string PersonId, string imageURI)
{
  var client = new HttpClient();
  client.DefaultRequestHeaders.Add("Ocp-Apim-Subscription-Key", subscription_key);
  var endpointURI = $"https://westus.api.cognitive.microsoft.com/face/v1.0/persongroups/{personGroupId}/persons/{personId}/persistedFaces";
  HttpResponseMessage response;
  var body = "{\"url\": \"" + imageURI + "\"}";
  var content = new StringContent(body, Encoding.UTF8, "application/json");
  var response = await client.PutAsync(endpointURI, content);
}

static void HyFunction(TextAnalyticsClient textAnalyticsClient, string text)
{
  var response = textAnalyticsClient.ExtractKeyPhrases(text);
  Console.WriteLine("Key phreses");

  foreach(string keyphrase in response.Value)
  {
    Console.writeLine($"{keyphrase}")
  }
}

